-- Margin Leads v2.7 Private Beta foundation
create extension if not exists pgcrypto;
create table if not exists public.workspaces(id uuid primary key default gen_random_uuid(),name text not null,slug text unique,owner_id uuid not null references auth.users(id) on delete cascade,plan text not null default 'beta',created_at timestamptz not null default now());
create table if not exists public.workspace_members(workspace_id uuid references public.workspaces(id) on delete cascade,user_id uuid references auth.users(id) on delete cascade,role text not null default 'owner',created_at timestamptz not null default now(),primary key(workspace_id,user_id));
create table if not exists public.campaigns(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,name text not null,source text,import_profile text,status text default 'active',settings jsonb not null default '{}'::jsonb,created_by uuid references auth.users(id),created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.leads(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,campaign_id uuid references public.campaigns(id) on delete set null,company text,contact_name text,role text,email text,website text,category text,product text,status text default 'new',fit_score integer default 0,data jsonb not null default '{}'::jsonb,created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.activity_logs(id bigint generated by default as identity primary key,workspace_id uuid references public.workspaces(id) on delete cascade,user_id uuid references auth.users(id) on delete set null,event_type text not null,entity_type text,entity_id text,metadata jsonb not null default '{}'::jsonb,created_at timestamptz default now());
alter table public.workspaces enable row level security;alter table public.workspace_members enable row level security;alter table public.campaigns enable row level security;alter table public.leads enable row level security;alter table public.activity_logs enable row level security;
create or replace function public.is_workspace_member(wid uuid) returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from public.workspace_members where workspace_id=wid and user_id=auth.uid()) or exists(select 1 from public.workspaces where id=wid and owner_id=auth.uid())$$;
create policy "workspace members can view workspaces" on public.workspaces for select using(public.is_workspace_member(id));
create policy "owners can create workspaces" on public.workspaces for insert with check(owner_id=auth.uid());
create policy "members can view memberships" on public.workspace_members for select using(public.is_workspace_member(workspace_id));
create policy "members manage campaigns" on public.campaigns for all using(public.is_workspace_member(workspace_id)) with check(public.is_workspace_member(workspace_id));
create policy "members manage leads" on public.leads for all using(public.is_workspace_member(workspace_id)) with check(public.is_workspace_member(workspace_id));
create policy "members view logs" on public.activity_logs for select using(public.is_workspace_member(workspace_id));
create policy "members create logs" on public.activity_logs for insert with check(public.is_workspace_member(workspace_id) and user_id=auth.uid());
